import React, { useState, useMemo } from 'react';

const theme = {
  bg: '#0a0a0a', surface: '#111111', surfaceAlt: '#1a1a1a',
  border: '#2a2a2a', text: '#fafafa', muted: '#a1a1aa', dim: '#52525b',
  blue: '#38bdf8', purple: '#8b5cf6', green: '#a3e635',
  yellow: '#fbbf24', orange: '#fb923c', red: '#f43f5e',
};

const presets = [
  { label: 'Small', n: 16, k: 2, d: 128 },
  { label: 'Medium', n: 64, k: 4, d: 256 },
  { label: 'Paper', n: 1000, k: 2, d: 512 },
];

function fmt(n) {
  if (n >= 1e9) return (n / 1e9).toFixed(2) + 'B';
  if (n >= 1e6) return (n / 1e6).toFixed(2) + 'M';
  if (n >= 1e3) return (n / 1e3).toFixed(1) + 'K';
  return n.toLocaleString();
}

export default function App() {
  const [n, setN] = useState(64);
  const [k, setK] = useState(4);
  const [d, setD] = useState(256);
  const [activePreset, setActivePreset] = useState(1);

  const { denseFlops, moeFlops, savings, ratio } = useMemo(() => {
    const dense = n * d * d;
    const moe = k * d * d;
    const sav = dense > 0 ? ((dense - moe) / dense) * 100 : 0;
    return {
      denseFlops: dense, moeFlops: moe,
      savings: Math.round(sav * 10) / 10,
      ratio: n > 0 ? k / n : 0,
    };
  }, [n, k, d]);

  const applyPreset = (p, idx) => {
    setN(p.n); setK(p.k); setD(p.d); setActivePreset(idx);
  };

  const getInsight = () => {
    if (savings >= 99) return 'Extreme sparsity! The MoE layer uses less than 1% of dense computation. This is how models scale to billions of parameters affordably.';
    if (savings >= 95) return 'Very high savings. Only a tiny fraction of experts are active, yet the model retains access to all expert knowledge via the gating network.';
    if (savings >= 75) return 'Good savings. Activating fewer experts reduces cost significantly while maintaining model capacity.';
    if (savings >= 50) return 'Moderate savings. Try reducing k further to see how MoE achieves dramatic efficiency gains.';
    return 'Low savings. The key insight of MoE is that k should be much smaller than n for maximum efficiency.';
  };

  const getSavingsColor = () => {
    if (savings >= 95) return theme.green;
    if (savings >= 75) return theme.yellow;
    if (savings >= 50) return theme.orange;
    return theme.red;
  };

  // Expert grid rendering
  const renderExpertGrid = () => {
    if (n <= 120) {
      const cols = Math.ceil(Math.sqrt(n * 2.2));
      const rows = Math.ceil(n / cols);
      const maxW = 540;
      const gap = n <= 20 ? 5 : n <= 50 ? 3 : 2;
      const cellSize = Math.min(Math.floor((maxW - (cols - 1) * gap) / cols), n <= 20 ? 32 : n <= 50 ? 20 : 14);
      const gridW = cols * cellSize + (cols - 1) * gap;
      const gridH = rows * cellSize + (rows - 1) * gap;

      return (
        <svg width={gridW} height={gridH} style={{ display: 'block', margin: '0 auto' }}>
          {Array.from({ length: n }, (_, i) => {
            const col = i % cols;
            const row = Math.floor(i / cols);
            const isActive = i < k;
            const x = col * (cellSize + gap);
            const y = row * (cellSize + gap);
            return (
              <rect
                key={i} x={x} y={y} width={cellSize} height={cellSize} rx={cellSize > 16 ? 4 : 2}
                fill={isActive ? theme.blue : theme.surfaceAlt}
                stroke={isActive ? theme.blue : theme.border}
                strokeWidth={isActive ? 1.5 : 0.5}
                opacity={isActive ? 1 : 0.5}
                style={{ transition: 'all 0.3s ease' }}
              />
            );
          })}
          {n <= 32 && Array.from({ length: n }, (_, i) => {
            const col = i % cols;
            const row = Math.floor(i / cols);
            const isActive = i < k;
            const x = col * (cellSize + gap) + cellSize / 2;
            const y = row * (cellSize + gap) + cellSize / 2;
            return cellSize >= 20 ? (
              <text
                key={'t' + i} x={x} y={y + 1}
                textAnchor="middle" dominantBaseline="central"
                fontSize={cellSize > 28 ? 10 : 8}
                fontFamily="'JetBrains Mono', monospace"
                fill={isActive ? '#0a0a0a' : theme.dim}
                fontWeight={isActive ? 700 : 400}
                style={{ transition: 'all 0.3s ease' }}
              >
                {isActive ? 'ON' : ''}
              </text>
            ) : null;
          })}
        </svg>
      );
    } else {
      // Proportional bar for large n
      const barW = 540;
      const barH = 48;
      const activeW = Math.max(2, (k / n) * barW);
      return (
        <svg width={barW} height={barH + 36} style={{ display: 'block', margin: '0 auto' }}>
          <rect x={0} y={0} width={barW} height={barH} rx={6} fill={theme.surfaceAlt} stroke={theme.border} strokeWidth={1} />
          <rect x={0} y={0} width={activeW} height={barH} rx={activeW < barW ? 0 : 6} fill={theme.blue} opacity={0.9} style={{ transition: 'width 0.4s ease' }}>
            <animate attributeName="opacity" values="0.7;1;0.7" dur="2s" repeatCount="indefinite" />
          </rect>
          {activeW > 8 && <rect x={0} y={0} width={activeW} height={barH} rx={0} fill={theme.blue} style={{ transition: 'width 0.4s ease' }} />}
          <text x={activeW < 60 ? activeW + 8 : activeW / 2} y={barH / 2} textAnchor={activeW < 60 ? 'start' : 'middle'} dominantBaseline="central" fontSize={13} fontFamily="'JetBrains Mono', monospace" fill={activeW < 60 ? theme.blue : '#0a0a0a'} fontWeight={700}>
            {k} active
          </text>
          <text x={barW - 6} y={barH / 2} textAnchor="end" dominantBaseline="central" fontSize={11} fontFamily="'JetBrains Mono', monospace" fill={theme.dim}>
            {n - k} inactive
          </text>
          <text x={0} y={barH + 18} fontSize={10} fontFamily="'JetBrains Mono', monospace" fill={theme.dim}>
            {k} of {n} experts activated ({(ratio * 100).toFixed(2)}%)
          </text>
        </svg>
      );
    }
  };

  const denseBarW = 480;
  const moeBarW = Math.max(3, ratio * denseBarW);

  return (
    <div style={{ maxWidth: 600, margin: '0 auto', minHeight: '100vh', background: theme.bg, color: theme.text, fontFamily: "'JetBrains Mono', monospace", padding: '20px 24px', boxSizing: 'border-box', display: 'flex', flexDirection: 'column', gap: 0 }}>

      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 700, letterSpacing: '-0.5px' }}>MoE Efficiency</div>
          <div style={{ fontSize: 11, color: theme.dim, marginTop: 2 }}>Mixture-of-Experts vs Dense Layer</div>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          {presets.map((p, i) => (
            <button key={i} onClick={() => applyPreset(p, i)} style={{
              background: activePreset === i ? theme.purple : theme.surfaceAlt,
              border: '1px solid ' + (activePreset === i ? theme.purple : theme.border),
              borderRadius: 6, padding: '5px 10px', cursor: 'pointer',
              fontSize: 11, fontWeight: 600, color: activePreset === i ? '#fff' : theme.muted,
              fontFamily: "'JetBrains Mono', monospace", transition: 'all 0.2s',
            }}>
              {p.label}
            </button>
          ))}
        </div>
      </div>

      {/* Expert Grid */}
      <div style={{ background: theme.surface, borderRadius: 12, padding: 16, marginBottom: 16 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
          <span style={{ fontSize: 11, color: theme.dim }}>EXPERT ACTIVATION</span>
          <span style={{ fontSize: 11, color: theme.blue, fontWeight: 600 }}>
            {k} / {n} experts active
          </span>
        </div>
        {renderExpertGrid()}
      </div>

      {/* k Slider - THE MAIN CONTROL */}
      <div style={{ background: theme.surface, borderRadius: 12, padding: 16, marginBottom: 16 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
          <span style={{ fontSize: 12, color: theme.muted }}>Active experts (k)</span>
          <span style={{ fontSize: 20, fontWeight: 700, color: theme.blue, minWidth: 60, textAlign: 'right' }}>{k}</span>
        </div>
        <input
          type="range" min={1} max={n} value={k}
          onChange={e => { setK(parseInt(e.target.value)); setActivePreset(-1); }}
          style={{ width: '100%', height: 8, cursor: 'pointer', accentColor: theme.blue }}
        />
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10, color: theme.dim, marginTop: 4 }}>
          <span>1 (max savings)</span>
          <span>{n} (no savings)</span>
        </div>
      </div>

      {/* FLOPs Comparison */}
      <div style={{ background: theme.surface, borderRadius: 12, padding: 16, marginBottom: 16 }}>
        <div style={{ fontSize: 11, color: theme.dim, marginBottom: 12 }}>FLOPs COMPARISON (d_in = d_out = {d})</div>

        <div style={{ marginBottom: 14 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: 5 }}>
            <span style={{ fontSize: 11, color: theme.muted }}>Dense (all {n} experts)</span>
            <span style={{ fontSize: 12, fontWeight: 600, color: theme.orange }}>{fmt(denseFlops)} FLOPs</span>
          </div>
          <div style={{ height: 20, background: theme.surfaceAlt, borderRadius: 4, overflow: 'hidden', position: 'relative' }}>
            <div style={{ height: '100%', width: '100%', background: theme.orange, borderRadius: 4, opacity: 0.8 }} />
          </div>
          <div style={{ fontSize: 9, color: theme.dim, marginTop: 3, fontFamily: 'monospace' }}>
            {n} x {d} x {d} = {denseFlops.toLocaleString()}
          </div>
        </div>

        <div style={{ marginBottom: 6 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: 5 }}>
            <span style={{ fontSize: 11, color: theme.muted }}>MoE ({k} active expert{k > 1 ? 's' : ''})</span>
            <span style={{ fontSize: 12, fontWeight: 600, color: theme.blue }}>{fmt(moeFlops)} FLOPs</span>
          </div>
          <div style={{ height: 20, background: theme.surfaceAlt, borderRadius: 4, overflow: 'hidden', position: 'relative' }}>
            <div style={{ height: '100%', width: `${Math.max(0.5, ratio * 100)}%`, background: theme.blue, borderRadius: 4, transition: 'width 0.4s ease', minWidth: 3 }} />
          </div>
          <div style={{ fontSize: 9, color: theme.dim, marginTop: 3, fontFamily: 'monospace' }}>
            {k} x {d} x {d} = {moeFlops.toLocaleString()}
          </div>
        </div>
      </div>

      {/* Savings Result */}
      <div style={{ background: theme.surface, borderRadius: 12, padding: 16, marginBottom: 16, textAlign: 'center' }}>
        <div style={{ fontSize: 11, color: theme.dim, marginBottom: 8 }}>COMPUTATIONAL SAVINGS</div>
        <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'center', gap: 4, marginBottom: 10 }}>
          <span style={{ fontSize: 42, fontWeight: 800, color: getSavingsColor(), transition: 'color 0.3s', letterSpacing: '-2px' }}>
            {savings}
          </span>
          <span style={{ fontSize: 20, fontWeight: 600, color: getSavingsColor(), transition: 'color 0.3s' }}>%</span>
        </div>

        {/* Savings bar */}
        <div style={{ height: 8, background: theme.surfaceAlt, borderRadius: 4, overflow: 'hidden', marginBottom: 6, position: 'relative' }}>
          <div style={{
            height: '100%', borderRadius: 4, transition: 'all 0.4s ease',
            width: `${savings}%`,
            background: `linear-gradient(90deg, ${theme.orange}, ${theme.yellow} 50%, ${theme.green})`,
          }} />
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: theme.dim }}>
          <span>0%</span><span>50%</span><span>100%</span>
        </div>
      </div>

      {/* Insight */}
      <div style={{
        background: theme.surfaceAlt, borderRadius: 10, padding: '12px 14px',
        borderLeft: '3px solid ' + theme.purple, fontSize: 11, color: theme.muted, lineHeight: 1.5,
      }}>
        <span style={{ color: theme.purple, fontWeight: 700 }}>Insight: </span>
        {getInsight()}
      </div>
    </div>
  );
}
